class Solution:
    def findLUSlength(self, a, b):
        if a == b:
            return -1
        return len(a) if len(a) > len(b) else len(b)

solutions.python:
class Solution:
    def findLUSlength(self, a, b):
        return -1 if a == b else max(len(a), len(b))

